class Solution:
    def insert(self, intervals: list[list[int]], newInterval: list[int]) -> list[list[int]]:
        res = []
        for i in range(len(intervals)):
            if newInterval[1] < intervals[i][0]:
                # newInterval ends before current starts → insert and copy rest
                res.append(newInterval)
                return res + intervals[i:]
            elif newInterval[0] > intervals[i][1]:
                # current ends before newInterval starts → add current
                res.append(intervals[i])
            else:
                # overlap → merge into newInterval
                newInterval[0] = min(newInterval[0], intervals[i][0])
                newInterval[1] = max(newInterval[1], intervals[i][1])
        # If we get here, newInterval overlaps or follows everything
        res.append(newInterval)
        return res

class Solution:
    def insert(self, intervals: list[list[int]], newInterval: list[int]) -> list[list[int]]:
        if not intervals:
            return [newInterval]
        # Binary search to find where newInterval would be inserted
        left, right = 0, len(intervals)
        while left < right:
            mid = (left + right) // 2
            if intervals[mid][0] < newInterval[0]:
                left = mid + 1
            else:
                right = mid
        # Now merge with overlapping neighbors
        res = []
        # Add all intervals before the overlap range
        i = 0
        while i < len(intervals) and intervals[i][1] < newInterval[0]:
            res.append(intervals[i])
            i += 1
        # Merge all overlapping intervals
        while i < len(intervals) and intervals[i][0] <= newInterval[1]:
            newInterval[0] = min(newInterval[0], intervals[i][0])
            newInterval[1] = max(newInterval[1], intervals[i][1])
            i += 1
        res.append(newInterval)
        # Add remaining intervals
        while i < len(intervals):
            res.append(intervals[i])
            i += 1
        return res

class Solution:
    def merge(self, intervals: list[list[int]]) -> list[list[int]]:
        intervals.sort(key=lambda x: x[0])  # sort by start
        merged = [intervals[0]]
        for start, end in intervals[1:]:
            if start <= merged[-1][1]:
                # overlaps → extend the last interval's end
                merged[-1][1] = max(merged[-1][1], end)
            else:
                # no overlap → add new interval
                merged.append([start, end])
        return merged

class Solution:
    def eraseOverlapIntervals(self, intervals: list[list[int]]) -> int:
        intervals.sort(key=lambda x: x[1])  # sort by end
        count = 0
        prevEnd = intervals[0][1]
        for start, end in intervals[1:]:
            if start < prevEnd:
                # overlap → remove this interval (it ends later or same)
                count += 1
            else:
                # no overlap → keep it
                prevEnd = end
        return count

class Solution:
    def eraseOverlapIntervals(self, intervals: list[list[int]]) -> int:
        intervals.sort(key=lambda x: x[0])  # sort by start
        n = len(intervals)
        # dp[i] = max non-overlapping intervals ending at i
        dp = [1] * n
        for i in range(1, n):
            for j in range(i):
                # intervals[j] and intervals[i] don't overlap if j ends before i starts
                if intervals[j][1] <= intervals[i][0]:
                    dp[i] = max(dp[i], dp[j] + 1)
        # Max non-overlapping = max(dp); removals = n - max
        return n - max(dp)

class Solution:
    def canAttendMeetings(self, intervals: list[list[int]]) -> bool:
        intervals.sort(key=lambda x: x[0])
        for i in range(1, len(intervals)):
            if intervals[i][0] < intervals[i - 1][1]:
                return False  # current starts before previous ends
        return True

import heapq

class Solution:
    def minMeetingRooms(self, intervals: list[list[int]]) -> int:
        if not intervals:
            return 0
        intervals.sort(key=lambda x: x[0])  # sort by start
        heap = []  # min-heap of end times
        for start, end in intervals:
            # Remove all meetings that have ended by this start time
            while heap and heap[0] <= start:
                heapq.heappop(heap)
            # Add this meeting's end time
            heapq.heappush(heap, end)
        # Max heap size = max overlapping meetings
        return len(heap)
